import{_ as a,o as e,c as s,a2 as d}from"./chunks/framework.BFVZdVmd.js";const u=JSON.parse('{"title":"灰度发布与服务网格","description":"","frontmatter":{},"headers":[],"relativePath":"deploy/mesh.md","filePath":"deploy/mesh.md","lastUpdated":null}'),n={name:"deploy/mesh.md"};function o(r,t,l,i,p,c){return e(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="灰度发布与服务网格" tabindex="-1">灰度发布与服务网格 <a class="header-anchor" href="#灰度发布与服务网格" aria-label="Permalink to &quot;灰度发布与服务网格&quot;">​</a></h1><p>把新版本逐步放量、按流量比例验证、出问题能快速回滚，是企业项目从&quot;能发布&quot;到&quot;能安全发布&quot;的关键。大型项目还会用服务网格统一治理服务间流量。</p><h2 id="常见组件" tabindex="-1">常见组件 <a class="header-anchor" href="#常见组件" aria-label="Permalink to &quot;常见组件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>类别</th><th>主要作用</th></tr></thead><tbody><tr><td>Istio</td><td>服务网格</td><td>服务间流量治理、mTLS、可观测性。</td></tr><tr><td>Linkerd</td><td>服务网格</td><td>轻量级服务网格。</td></tr><tr><td>Argo Rollouts</td><td>灰度发布</td><td>蓝绿、金丝雀等渐进式发布。</td></tr><tr><td>Gateway + Nacos</td><td>简单灰度</td><td>基于网关和元数据的灰度路由。</td></tr><tr><td>Kubernetes Ingress</td><td>流量入口</td><td>集群流量入口。</td></tr><tr><td>Envoy</td><td>高性能代理</td><td>服务网格数据面代理。</td></tr></tbody></table><h2 id="大型项目的发布与治理需求" tabindex="-1">大型项目的发布与治理需求 <a class="header-anchor" href="#大型项目的发布与治理需求" aria-label="Permalink to &quot;大型项目的发布与治理需求&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>蓝绿发布</span></span>
<span class="line"><span>金丝雀发布</span></span>
<span class="line"><span>灰度发布</span></span>
<span class="line"><span>流量镜像</span></span>
<span class="line"><span>mTLS</span></span>
<span class="line"><span>服务间流量治理</span></span></code></pre></div><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><ul><li>普通中小项目可以先不用服务网格，复杂度比较高。简单灰度用 <a href="/my-docs/framework/gateway">Gateway</a> + <a href="/my-docs/framework/nacos">Nacos</a> 元数据路由即可。</li><li>需要蓝绿/金丝雀发布：<code>Argo Rollouts</code>。</li><li>大型项目、服务间需要 mTLS 和精细流量治理：再考虑 <code>Istio</code>。</li><li>服务网格依赖 <a href="./kubernetes">Kubernetes</a>，应在容器编排成熟后再引入。</li></ul>`,8)])])}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
